		private StatisticsEstimate estimateUnary(UnaryTupleOperator operator, Set<String> boundVars, String method) {
			StatisticsEstimate input = estimate(operator.getArg(), boundVars);
			return estimateUnary(operator, input, method);
		}

		private StatisticsEstimate estimateUnary(UnaryTupleOperator operator, StatisticsEstimate input, String method) {
			return StatisticsEstimate.fromBag(input.bag()
					.withWorkRows(input.workRows() + Math.max(1.0d, input.rows() * 0.05d),
							method + "-pass-through"),
					method);
		}

		private StatisticsEstimate estimateDistinct(UnaryTupleOperator operator, Set<String> boundVars) {
			StatisticsEstimate input = estimate(operator.getArg(), boundVars);
			return estimateDistinct(operator, input);
		}

		private StatisticsEstimate estimateDistinct(UnaryTupleOperator operator, StatisticsEstimate input) {
			StatisticsEstimate estimate = rdfStatisticsProvider.distinct(input, operator.getBindingNames())
					.orElseGet(() -> StatisticsEstimate.fromBag(EstimateMath.distinct(input.bag(),
							operator.getBindingNames()), "distinct"));
			return estimate.withMetric("plannedMemoryRows", estimate.bag().memoryRows());
		}

		private StatisticsEstimate estimateReduced(Reduced reduced, Set<String> boundVars) {
			StatisticsEstimate input = estimate(reduced.getArg(), boundVars);
			return estimateReduced(reduced, input, reduced.getArg() instanceof Order);
		}

		private StatisticsEstimate estimateReduced(Reduced reduced, StatisticsEstimate input, boolean exact) {
			double inputRows = Math.max(0.0d, input.rows());
			double workRows = input.workRows() + inputRows;
			double memoryRows = Math.max(input.bag().memoryRows(), inputRows > 0.0d ? 1.0d : 0.0d);
			Map<String, Double> metrics = new LinkedHashMap<>(input.metrics());
			metrics.put("plannedReducedInputRows", inputRows);
			metrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
			metrics.put("plannedMemoryRows", memoryRows);
			if (exact) {
				StatisticsEstimate cardinality = estimateDistinct(reduced, input);
				BagEstimate bag = cardinality.bag()
						.withWorkRows(workRows, "ordered-reduced")
						.withMemoryRows(memoryRows, "ordered-reduced")
						.withMetrics(metrics);
				return new StatisticsEstimate(bag.rows(), cardinality.qErrorInterval(), bag.workRows(),
						"ordered-reduced", metrics, bag);
			}
			BagEstimate bag = input.bag()
					.withRowsPreservingEvidence(inputRows, workRows, input.qErrorInterval().confidence(),
							"reduced-consecutive", metrics, false)
					.withMemoryRows(memoryRows, "reduced-consecutive")
					.withMetrics(metrics);
			return new StatisticsEstimate(inputRows, input.qErrorInterval(), workRows, "reduced-consecutive", metrics,
					bag);
		}

		private StatisticsEstimate estimateProjection(Projection projection, Set<String> boundVars) {
			StatisticsEstimate input = estimate(projection.getArg(), boundVars);
			return estimateProjection(projection, input);
		}

		private StatisticsEstimate estimateProjection(Projection projection, StatisticsEstimate input) {
			BagEstimate bag = input.bag();
			for (ProjectionElem element : projection.getProjectionElemList().getElements()) {
				String sourceName = element.getName();
				String targetName = element.getProjectionAlias().orElse(sourceName);
				if (!sourceName.equals(targetName)) {
					bag = EstimateMath.extendAlias(bag, sourceName, targetName);
				}
			}
			return StatisticsEstimate.fromBag(EstimateMath.project(bag, projection.getBindingNames()), "projection");
		}

		private StatisticsEstimate estimateExtension(Extension extension, Set<String> boundVars) {
			StatisticsEstimate input = estimate(extension.getArg(), boundVars);
			return estimateExtension(extension, input);
		}

		private StatisticsEstimate estimateExtension(Extension extension, StatisticsEstimate input) {
			BagEstimate bag = input.bag();
			for (ExtensionElem element : extension.getElements()) {
				ValueExpr expr = element.getExpr();
				if (expr instanceof ValueConstant) {
					bag = EstimateMath.extendConstant(bag, element.getName());
				} else if (expr instanceof Var var && var.getName() != null) {
					bag = EstimateMath.extendAlias(bag, var.getName(), element.getName());
				} else {
					bag = bag.withVariable(element.getName(), VariableEstimate.bound(bag.rows(), bag.rows()));
				}
			}
			return StatisticsEstimate.fromBag(bag.withWorkRows(input.workRows() + Math.max(1.0d, input.rows()),
					"extension-work"), "extension");
		}

		private StatisticsEstimate estimateGroup(Group group, Set<String> boundVars) {
			StatisticsEstimate input = estimate(group.getArg(), boundVars);
			return estimateGroup(group, input);
		}

		private StatisticsEstimate estimateGroup(Group group, StatisticsEstimate input) {
			BagEstimate bag = EstimateMath.group(input.bag(), group.getGroupBindingNames());
			for (String aggregateName : group.getAggregateBindingNames()) {
				bag = bag.withVariable(aggregateName, VariableEstimate.bound(bag.rows(), bag.rows()));
			}
			return StatisticsEstimate.fromBag(bag, "group");
		}

